export const scalePixelArt = (image: string, scale: number): string => {
  if (image === "") return "";
  const rows = image.split("\n");
  const scaledRows = rows.map((row) =>
    row
      .split("")
      .map((char) => char.repeat(scale))
      .join(""),
  );
  const result: string[] = [];
  for (const scaledRow of scaledRows) {
    for (let i = 0; i < scale; i++) {
      result.push(scaledRow);
    }
  }
  return result.join("\n");
};

